css:
/* Layout & Direction */
.print-frame { 
    width: 100%; 
    border-collapse: collapse; 
    direction: rtl; /* جعل الاتجاه يبدأ من اليمين */
    text-align: right; 
}
.print-format-container { padding: 10px; font-family: Arial, sans-serif; }

/* Header Titles */
.eiu-header-text { text-align: center; margin-bottom: 20px; }
.form-badge {
    display: inline-block;
    padding: 8px 25px;
    background: #f2f2f2;
    border: 1px solid #333;
    font-weight: bold;
    font-size: 16px;
}

.section-title-box {
    background-color: #1a4d80;
    color: white;
    padding: 5px 12px;
    font-weight: bold;
    margin-top: 15px;
    border: 1px solid #1a4d80;
    text-align: right;
}

/* Table Styling for RTL */
.doc-table { width: 100%; border-collapse: collapse; margin-bottom: 5px; }
.doc-table th, .doc-table td {
    border: 1px solid #333;
    padding: 8px;
    font-size: 11px;
    text-align: right; /* محاذاة النص لليمين */
}
.doc-table th { background-color: #f2f2f2; width: 22%; font-weight: bold; }

/* Checkboxes RTL */
.checkbox-container {
    display: flex;
    flex-direction: row;
    justify-content: space-around;
    padding: 10px;
    border: 1px solid #333;
    border-top: none;
    margin-bottom: 10px;
}
.check-item { font-size: 11px; display: flex; align-items: center; gap: 5px; }

/* Signatures Grid */
.signature-grid {
    display: flex;
    flex-direction: row; /* الحفاظ على ترتيب الصناديق أفقياً */
    justify-content: space-between;
    margin-top: 40px;
}
.sig-box { width: 23%; text-align: center; }
.sig-name { height: 25px; font-weight: bold; color: #1a4d80; font-size: 10px; display: flex; align-items: flex-end; justify-content: center; }
.sig-line { border-top: 1px solid #000; margin: 5px 0; }
.sig-box p { font-size: 9px; margin: 0; font-weight: bold; }

/* Footer */
.page-footer-wrapper { border-top: 1px solid #ccc; padding-top: 5px; margin-top: 15px; }
.page-footer { display: flex; justify-content: space-between; font-size: 9px; color: #666; direction: rtl; }
/* 1. الأيقونات العامة (التي تظهر على الخلفية البيضاء) */
    .icon::before {
        font-family: "FontAwesome";
        display: inline-block;
        margin-left: 8px;
        font-weight: normal;
        color: #444444; /* لون رمادي غامق جداً ليظهر بوضوح على الورق الأبيض */
    }

    /* 2. الأيقونات الخاصة بالعناوين (التي تظهر فوق الخلفية الزرقاء) */
    .section-title-box .icon::before {
        color: #ffffff !important; /* لون أبيض ناصع ليظهر بوضوح فوق الأزرق */
    }

    /* كود الرموز (Unicode) للأيقونات */
    .icon-user::before { content: "\f007"; }
    .icon-id::before { content: "\f2c2"; }
    .icon-dept::before { content: "\f0e8"; }
    .icon-date::before { content: "\f017"; }
    .icon-phone::before { content: "\f095"; }
    .icon-map::before { content: "\f041"; }
    .icon-calendar::before { content: "\f073"; }
    .icon-check::before { content: "\f046"; }
    .icon-print::before { content: "\f02f"; }
    .icon-university::before { content: "\f19c"; }
    .icon-exchange::before { content: "\f0ec"; }
    .icon-hourglass::before { content: "\f252"; }
